class Solution {
    public List<Long> maximumEvenSplit(long finalSum) {
        List<Long> result = new ArrayList<>();
        for (long i = 2; i <= finalSum / 2; i += 2) {
            if (finalSum >= i) {
                result.add(i);
                finalSum -= i;
            }
        }
        if (finalSum > 0) {
            result.clear();
        }
        return result;
    }
}
